import{_ as a,o as i,c as t,a2 as r}from"./chunks/framework.Bix3-HpO.js";const u=JSON.parse('{"title":"Privacy & GDPR","description":"Data Collection and Privacy in Nonaki","frontmatter":{"title":"Privacy & GDPR","description":"Data Collection and Privacy in Nonaki","weight":90,"extra":{"order":90},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/nonaki/privacy"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/nonaki/privacy"}],["meta",{"property":"og:title","content":"Privacy & GDPR"}],["meta",{"property":"og:description","content":"Data Collection and Privacy in Nonaki"}],["meta",{"name":"twitter:title","content":"Privacy & GDPR"}],["meta",{"name":"twitter:description","content":"Data Collection and Privacy in Nonaki"}]]},"headers":[],"relativePath":"docs/nonaki/privacy.md","filePath":"docs/nonaki/privacy.md"}'),o={name:"docs/nonaki/privacy.md"};function s(n,e,l,d,c,h){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="privacy-gdpr" tabindex="-1">Privacy &amp; GDPR <a class="header-anchor" href="#privacy-gdpr" aria-label="Permalink to &quot;Privacy &amp; GDPR&quot;">​</a></h1><p>This page describes what data Nonaki collects, how long it is kept, and what tools are available to manage it.</p><hr><h2 id="what-data-is-collected" tabindex="-1">What Data Is Collected <a class="header-anchor" href="#what-data-is-collected" aria-label="Permalink to &quot;What Data Is Collected&quot;">​</a></h2><h3 id="clicks" tabindex="-1">Clicks <a class="header-anchor" href="#clicks" aria-label="Permalink to &quot;Clicks&quot;">​</a></h3><p>When a visitor follows one of your redirect links, Nonaki records:</p><ul><li>Timestamp</li><li>Device type, browser, and operating system (derived from User-Agent)</li><li>Country (from CDN headers if available, otherwise from GeoIP if configured)</li><li>Referrer URL</li><li>A hashed version of the visitor&#39;s IP address (see below)</li><li>Whether the visitor was identified as a bot</li></ul><h3 id="impressions" tabindex="-1">Impressions <a class="header-anchor" href="#impressions" aria-label="Permalink to &quot;Impressions&quot;">​</a></h3><p>When a page on your site containing a Nonaki link is viewed, Nonaki records:</p><ul><li>Timestamp</li><li>Device type, browser, and operating system</li><li>Country (from CDN headers if available, otherwise from GeoIP if configured)</li><li>The URL of the page where the link appeared</li><li>A hashed version of the visitor&#39;s IP address</li></ul><hr><h2 id="ip-address-handling" tabindex="-1">IP Address Handling <a class="header-anchor" href="#ip-address-handling" aria-label="Permalink to &quot;IP Address Handling&quot;">​</a></h2><p>Raw IP addresses are stored temporarily in an internal processing queue and are deleted within approximately 5 minutes after the background processor runs.</p><p>For long-term storage, the IP address is converted to a one-way hash (SHA-256 with a site-specific salt). This hash cannot be reversed back to the original IP address. It is used only to deduplicate impressions within short time windows — it cannot be used to identify a visitor.</p><hr><h2 id="what-is-not-stored" tabindex="-1">What Is Not Stored <a class="header-anchor" href="#what-is-not-stored" aria-label="Permalink to &quot;What Is Not Stored&quot;">​</a></h2><ul><li>Full IP addresses in analytics (only hashed)</li><li>Cookies or browser fingerprints</li></ul><hr><h2 id="your-responsibilities-as-a-site-owner" tabindex="-1">Your Responsibilities as a Site Owner <a class="header-anchor" href="#your-responsibilities-as-a-site-owner" aria-label="Permalink to &quot;Your Responsibilities as a Site Owner&quot;">​</a></h2><p>All data described on this page is collected by you, on your website, from your visitors. DinoMatic does not receive, access, or store any of it — the plugin runs entirely within your WordPress installation.</p><p>As the site owner, you are the data controller under GDPR and similar regulations. You should:</p><ul><li>Disclose analytics tracking in your privacy policy</li><li>Ensure your use of visitor data complies with the laws applicable to your site and audience</li></ul><hr><h2 id="clearing-analytics-data" tabindex="-1">Clearing Analytics Data <a class="header-anchor" href="#clearing-analytics-data" aria-label="Permalink to &quot;Clearing Analytics Data&quot;">​</a></h2><p>The <code>Clear All Analytics</code> button in <strong>Settings</strong> permanently deletes all recorded clicks, impressions, and queue entries. This can be used to respond to a GDPR erasure request or to start fresh.</p><p>Individual link analytics are also deleted when a link is permanently force-deleted from the Trash.</p>',26)])])}const y=a(o,[["render",s]]);export{u as __pageData,y as default};
